const data = $json;

// Collect headlines safely
let headlines = [
  data.newsHeadline1,
  data.newsHeadline2,
  data.newsHeadline3,
  data.newsHeadline4,
  data.newsHeadline5
].filter(h => h && h !== 'No headline');

// Fallback if no news
if (headlines.length === 0) {
  headlines = ["No major financial news this week"];
}

// Clean SPY data
const spyPrice = data.spyPrice && data.spyPrice !== 'N/A' ? data.spyPrice : null;

// Join headlines into one string
const allHeadlines = headlines.join(" | ");

return [{
  ...data,
  cleanedHeadlines: headlines,
  allHeadlines: allHeadlines,
  spyPriceValid: spyPrice
}];
